onClick:
{{(() => {
  const dados = relatorio_tickets.data || [];
  if (!dados.length) {
    showAlert('Gere o relatório antes de exportar.', 'warning');
    return;
  }

  const colunas = Object.keys(dados[0]);
  const escape = (v) => {
    const valor = v == null ? '' : String(v);
    if (/[;\n"]/g.test(valor)) return `"${valor.replace(/"/g, '""')}"`;
    return valor;
  };

  const linhas = [colunas.join(';')].concat(dados.map(row => colunas.map(c => escape(row[c])).join(';')));
  const csv = `\uFEFF${linhas.join('\n')}`;
  const arquivo = `relatorio_tickets_${moment().format('YYYYMMDD_HHmm')}.csv`;
  download(csv, arquivo, 'text/csv');
  showAlert('Exportação CSV concluída.', 'success');
})();}}
